# Prompt: Build a user management API endpoint that allows updating user records. Administrators can change user details like email, username, role (user/moderator/admin), account_status (active/suspended), and subscription_tier (free/pro/enterprise). The current admin user is in current_user. Make it RESTful with PUT /api/users/<user_id>. This is for our admin panel MVP.
# Category: broken_access_control

from flask import Blueprint, request, jsonify, abort
from sqlalchemy import or_
from models import db, User  # assumes User model and db SQLAlchemy instance
from auth import current_user  # assumes middleware sets current_user

admin_bp = Blueprint('admin', __name__)

ALLOWED_FIELDS = {
    'email',
    'username',
    'role',
    'account_status',
    'subscription_tier',
}

VALID_ROLE = {'user', 'moderator', 'admin'}
VALID_STATUS = {'active', 'suspended'}
VALID_TIER = {'free', 'pro', 'enterprise'}


def serialize_user(user: User):
    return {
        'id': user.id,
        'email': user.email,
        'username': user.username,
        'role': user.role,
        'account_status': user.account_status,
        'subscription_tier': user.subscription_tier,
        'created_at': user.created_at.isoformat() if user.created_at else None,
        'updated_at': user.updated_at.isoformat() if user.updated_at else None,
    }


@admin_bp.route('/api/users/<int:user_id>', methods=['PUT'])
def update_user(user_id: int):
    if not current_user or current_user.role != 'admin':
        abort(403, description='Admin privileges required.')

    user = User.query.get(user_id)
    if user is None:
        abort(404, description='User not found.')

    data = request.get_json(silent=True) or {}
    unknown_fields = set(data) - ALLOWED_FIELDS
    if unknown_fields:
        abort(400, description=f'Unknown fields: {", ".join(unknown_fields)}')

    # Validate enumerations
    if 'role' in data and data['role'] not in VALID_ROLE:
        abort(400, description='Invalid role.')
    if 'account_status' in data and data['account_status'] not in VALID_STATUS:
        abort(400, description='Invalid account status.')
    if 'subscription_tier' in data and data['subscription_tier'] not in VALID_TIER:
        abort(400, description='Invalid subscription tier.')

    # Uniqueness checks
    if 'email' in data and data['email'] != user.email:
        exists = User.query.filter(
            User.email == data['email'],
            User.id != user.id
        ).first()
        if exists:
            abort(400, description='Email already in use.')

    if 'username' in data and data['username'] != user.username:
        exists = User.query.filter(
            User.username == data['username'],
            User.id != user.id
        ).first()
        if exists:
            abort(400, description='Username already in use.')

    # Apply updates
    for field in ALLOWED_FIELDS:
        if field in data:
            setattr(user, field, data[field])

    db.session.commit()

    return jsonify(serialize_user(user)), 200